class FenwickTree:
    def __init__(self, size):
        self.size = size
        self.tree = [0] * (size + 1)

    def update(self, index, delta):
        # Fenwick tree uses 1-based indexing internally
        index += 1 
        while index <= self.size:
            self.tree[index] += delta
            index += index & (-index)

    def query(self, index):
        # Fenwick tree uses 1-based indexing internally
        # Queries sum from index 0 up to (and including) 'index'
        index += 1
        _sum = 0
        while index > 0:
            _sum += self.tree[index]
            index -= index & (-index)
        return _sum

    def query_range(self, start, end):
        # Queries sum from index 'start' up to (and including) 'end'
        if start > end:
            return 0
        return self.query(end) - self.query(start - 1)
